          border: none;
          background: transparent;
          cursor: pointer;
          text-align: left;
          transition: background 0.15s;
          border-bottom: 1px solid #f1f5f9;
          position: relative;
        }
        
        .notif-item:hover {
          background: #f8f9fb;
        }
        
        .notif-item.unread {
          background: rgba(59, 130, 246, 0.02);
