        .notif-item.unread::before {
          content: '';
          position: absolute;
          left: 0;
          top: 0;
          bottom: 0;
          width: 3px;
          background: #3b82f6;
        }
        
        .notif-item.critical.unread::before {
          background: #dc2626;
        }
        
        .notif-item.high.unread::before {
          background: #f59e0b;
        }
        
        .notif-icon {
