        .notif-loading, .notif-empty {
          text-align: center;
          padding: 2rem 1rem;
          color: #8a96a8;
        }
        
        .notif-loading {
          display: flex;
          flex-direction: column;
          align-items: center;
          gap: 0.5rem;
        }
        
        .notif-empty > div {
          font-size: 0.85rem;
          font-weight: 600;
          color: #1a1f2e;
          margin-top: 0.5rem;
        }
        
        .notif-empty span {
          font-size: 0.7rem;
        }
        
        .notif-footer {
          padding: 0.5rem 1rem;
          border-top: 1px solid #e2e8f0;
          background: #f8f9fb;
        }
        
        .notif-view-all {
          width: 100%;
          padding: 0.5rem;
          background: transparent;
          border: 1px solid #e2e8f0;
          border-radius: 8px;
          font-size: 0.75rem;
          font-weight: 600;
          color: #4a5568;
          cursor: pointer;
          transition: all 0.15s;
        }
        
        .notif-view-all:hover {
          background: white;
          border-color: #C9A84C;
          color: #9a7a2e;
        }
        
        .spin {
          animation: spin 1s linear infinite;
        }
        
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }

